### 3.4 з§»еҠЁз«ҜиҜ·жұӮзӯҫеҗҚ

```kotlin
// жҜҸдёӘиҜ·жұӮйҷ„еҠ зӯҫеҗҚпјҲйҳІйҮҚж”ҫж”»еҮ»пјү
fun signRequest(request: Request, appSecret: String): Request {
    val timestamp = System.currentTimeMillis()
    val nonce = generateNonce()
    val sign = sha256("${appId}${timestamp}${nonce}${appSecret}")

    return request.newBuilder()
        .addHeader("X-App-ID", appId)
        .addHeader("X-Timestamp", timestamp.toString())
        .addHeader("X-Nonce", nonce)
        .addHeader("X-Sign", sign)
        .build()
}
```

### 3.5 Token иҮӘеҠЁеҲ·ж–°пјҲSDK е®һзҺ°пјү

```typescript
class SSOClient {
  async requestWithToken(apiRequest) {
    if (this.isTokenExpiringSoon()) {
      await this.refreshTokenSilently();
    }
    return this.executeRequest(apiRequest);
  }

  private async refreshTokenSilently() {
    try {
      const newToken = await this.callRefreshAPI();
      this.saveToken(newToken);
    } catch (e) {
      this.redirectToLogin();
    }
  }
}
```

